mapper.select:
		/* com.erns.coching.member.mapper.MemberWithdrawInfoDAO.getWithdrwalDetailStatistics */

		SELECT
    		/* 탈회 */
		    (SELECT COUNT(*) FROM T_MEMB

		    		AND WTDR_YN ='Y'

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		    ) AS WTHDR_CNT
		    ,(SELECT COUNT(DISTINCT M1.MEMB_SEQ)
		        FROM T_MEMB M1
		            JOIN T_BUSINESS_LIC_INF B1 ON M1.MEMB_SEQ = B1.MEMB_SEQ

		    		AND WTDR_YN ='Y'

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		        ) AS WTHDR_BIZ_CNT /* 사업자연동 탈회*/
		    ,(SELECT COUNT(DISTINCT M1.MEMB_SEQ)
		        FROM T_MEMB M1
		            JOIN T_BUSINESS_LIC_INF B1 ON M1.MEMB_SEQ = B1.MEMB_SEQ
		            JOIN TB_SC_ACC_INF_DAMO SAI ON B1.CLIENT_NO = SAI.CLIENT_NO

		    		AND WTDR_YN ='Y'
		    		AND (
									(SAI.ORG_CD = 'scd' AND (SAI.JOIN_YN = 'Y' OR SAI.JOIN_YN = 'F') )
		          OR 	(SAI.ORG_CD = 'card')
							)

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		        ) AS  WTHDR_2ND_CNT /* 카드연동 탈회 */
		    ,(SELECT COUNT(DISTINCT M1.MEMB_SEQ)
		        FROM T_MEMB M1
		            JOIN T_BUSINESS_LIC_INF B1 ON M1.MEMB_SEQ = B1.MEMB_SEQ
		            JOIN TB_SC_ACC_INF_DAMO SAI ON B1.CLIENT_NO = SAI.CLIENT_NO

		        	AND WTDR_YN ='Y'
		    		AND SAI.ORG_CD IN ('mall', 'dlvy', 'bank', 'hometax')

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		        ) AS  WTHDR_3RD_CNT /* 3단계연동 탈회 */

		    /* 탈회자 유지 기간 */
		  	,(SELECT count(*)
    			FROM T_MEMB

		    		AND WTDR_YN ='Y'
		    		AND (TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) >= 365

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		      ) AS MORE_THAN_ONE_YEAR/* 1년 이상 유지 */
		  	,(SELECT count(*)
    			FROM T_MEMB

		    		AND WTDR_YN ='Y'
		    		AND ((TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) >= 90
		    			AND (TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) < 365)

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		      ) AS MORE_THAN_NINTY /* 90일 이상 */
		  	,(SELECT count(*)
    			FROM T_MEMB

		    		AND WTDR_YN ='Y'
		    		AND ((TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) >= 30
		    			AND (TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) < 90)

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		      ) AS MORE_THAN_THIRTY /* 30일 이상 */
		  	,(SELECT count(*)
    			FROM T_MEMB

		    		AND WTDR_YN ='Y'
		    		AND ((TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) < 30
		    			AND (TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) >= 7)

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		      ) AS LESS_THEN_THIRTY /* 30일 미만 */
		  	,(SELECT count(*)
    			FROM T_MEMB

		    		AND WTDR_YN ='Y'
		    		AND (TO_DATE(WTDR_DTTM, 'YYYY-MM-DD') - TO_DATE(JOIN_DTTM, 'YYYY-MM-DD')) < 7

		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(WTDR_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


		      ) AS LESS_THEN_SEVEN /* 7일 미만 */
		FROM DUAL

/* com.erns.coching.member.mapper.MemberWithdrawInfoDAO.getWithdrawReason */
SELECT COUNT(AA.WTHDR_RSN) WTHDR_RSN_CNT , CD.CODE_NAME AS WTHDR_RSN , CD.SORT_ORD FROM T_CODE_INF CD LEFT OUTER JOIN (SELECT WTHDR_RSN FROM T_MEMB_WTHDR_INF
AND TO_CHAR(RGT_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}
AND TO_CHAR(RGT_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}
) AA ON CD.CODE = AA.WTHDR_RSN WHERE CD.CODE IN ('UW_00010', 'UW_00020', 'UW_00030','UW_00040', 'UW_09000') GROUP BY AA.WTHDR_RSN, CD.CODE_NAME, CD.SORT_ORD, CD.CODE
ORDER BY CD.SORT_ORD

		/* com.erns.coching.member.mapper.MemberWithdrawInfoDAO.getWithdrawReasonText */


    	SELECT * FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
				SELECT

				FROM T_MEMB_WTHDR_INF AA

					AND AA.WTHDR_RSN = 'UW_09000'

		    			AND TO_CHAR(AA.RGT_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


		    			AND TO_CHAR(AA.RGT_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}


				ORDER BY AA.WTHDR_SEQ DESC
			) A
		)

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

		/* com.erns.coching.member.mapper.MemberWithdrawInfoDAO.getWithdrawReasonTextCount */

		SELECT COUNT(*)
		FROM T_MEMB_WTHDR_INF AA

			AND AA.WTHDR_RSN = 'UW_09000'

    			AND TO_CHAR(AA.RGT_DTTM, 'YYYY-MM-DD') >= #{wtdrFromDate}


    			AND TO_CHAR(AA.RGT_DTTM, 'YYYY-MM-DD') <= #{wtdrToDate}
